document.addEventListener("DOMContentLoaded",()=>{const e=document.getElementById("page-transition");e&&document.querySelectorAll("a[href]").forEach(n=>{const t=n.getAttribute("href");t&&!t.startsWith("#")&&!t.startsWith("http")&&!t.startsWith("mailto:")&&n.addEventListener("click",i=>{i.preventDefault(),e.classList.add("active"),setTimeout(()=>{window.location.href=t},400)})})});
